effect.shader:
vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

mat2 rot2d( float a ) {
    return mat2(
        cos(a), -sin(a),
        sin(a), cos(a)
    );
}

void main() {

    vec2 st = acLayerNorm;

    float a = angle * 0.0174533;

    st -= 0.5;
    st *= rot2d(a);
    st += 0.5;

    st.y = floor((st.y + phase / 10.) * amount) / amount - phase / 10.;

    st -= 0.5;
    st *= rot2d(-a);
    st += 0.5;

    //st = mod(st + 1000., 1.);

    vec4 baseColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec4 texColor = texture2DCv(inputImg.texture,l2s(st));

    vec4 c = mix(baseColor,texColor,alpha);

    if(maskToLayer) {
        c *= baseColor.a;
        gl_FragColor = baseColor * (1.-c.a) + c;
    } else {
        gl_FragColor = c;
    }
}
